def build_system_prompt(
    role: str,
    constraints: list[str],
    environment: dict[str, str],
    output_format: str = "",
    tool_guidance: str = "",
) -> str:
    """
    Build a structured system prompt from components.
    Returns a stable string suitable for API caching.
    """
    parts = [role.strip()]

    if constraints:
        parts.append("Constraints:\n" + "\n".join(f"- {c}" for c in constraints))

    if environment:
        env_lines = "\n".join(f"- {k}: {v}" for k, v in environment.items())
        parts.append(f"Environment:\n{env_lines}")

    if output_format:
        parts.append(f"Output format:\n{output_format.strip()}")

    if tool_guidance:
        parts.append(f"Tool guidance:\n{tool_guidance.strip()}")

    return "\n\n".join(parts)


SYSTEM = build_system_prompt(
    role=(
        "You are a coding agent for a Python web service. "
        "Your goal is to fix bugs without changing test files."
    ),
    constraints=[
        "Never modify files in tests/.",
        "Keep changes minimal — fix only what is broken.",
        "Do not install new packages without approval.",
    ],
    environment={
        "Repository root": "/workspace/myapp",
        "Entry point": "src/app.py",
        "Test suite": "pytest tests/",
        "Python version": "3.12",
    },
    output_format=(
        "After each tool call, explain what you did.\n"
        "When done, summarise all changes in one paragraph."
    ),
)
